import axios from "axios"
import { useState } from "react"
import { Link } from "react-router-dom"


const LoginPage =()=>{

  const [logData,setLogData] = useState({
    email:'',
    password:''
  })

   async function handlelSubmit(e){
    e.preventDefault()
    try {
      const {data}= await axios.post('/auth/login',logData)
      axios.defaults.headers.common.Authorization = `Bearer ${data.token}`
      console.log(data)
    } catch (error) {
      console.log(error)
    }
   }

    return <div>
      <div>
      <h1 className="mx-auto m-4 w-28">Login PAGE</h1>
      <div>
        <form action="" className="flex justify-center"  onSubmit={handleSubmit}>
          <div className="flex flex-col w-96 ">
            <input type="text" placeholder="EMAIL" name="email" value={logData.email} onChange={handleChange}/>
            <input type="text" placeholder="PASSWORD" name="password" value={logData.password} onChange={handleChange}/>
            <button className="">LOG IN</button>
          </div>
        </form>
      </div>
    </div>
    </div>
}

export default LoginPage;
